diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..ef69d14c5267 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3493,6 +3493,102 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (!LHSC || !RHSC)
     return nullptr;

+  // (icmp eq (X & Mask), C2) & (icmp ult/ule X, C1) -> (icmp eq (X & Mask), C2)
+  // (icmp ne (X & Mask), C2) | (icmp uge/ugt X, C1) -> (icmp ne (X & Mask), C2)
+  // iff all X satisfying (X & Mask) == C2 also satisfy the range check.
+  // The maximum X satisfying (X & Mask) == C2 is (C2 | ~Mask).
+  // Also handle the signed variants.
+  // Additionally, handle cases where the two conditions can be merged into one
+  // range check: (icmp ult X, C1) | (icmp eq (X & Mask), C2) -> (icmp ult X, C1+1)
+  // when the masked values are adjacent; and
+  // (icmp ugt X, C1) & (icmp ne (X & Mask), C2) -> (icmp ugt X, C2|~Mask)
+  // when the excluded masked values start at C1+1.
+  {
+    auto MatchMaskedEqAndRangeCheck = [&](ICmpInst *MaskedCmp, ICmpInst *RangeCmp,
+                                           bool IsAnd) -> Value * {
+      CmpPredicate MaskPred;
+      Value *X;
+      const APInt *Mask, *C2;
+      // Match (X & Mask) == C2 or C2 == (X & Mask)
+      if (!match(MaskedCmp, m_c_ICmp(MaskPred,
+                                      m_And(m_Value(X), m_APIntAllowPoison(Mask)),
+                                      m_APIntAllowPoison(C2))))
+        return nullptr;
+
+      if (X != RangeCmp->getOperand(0))
+        return nullptr;
+
+      CmpPredicate RangePred;
+      const APInt *C1;
+      if (!match(RangeCmp, m_ICmp(RangePred, m_Specific(X), m_APInt(C1))))
+        return nullptr;
+
+      APInt MaxVal = *C2 | ~*Mask;
+      APInt MinVal = *C2;
+
+      if (IsAnd) {
+        // (icmp eq (X & Mask), C2) & (icmp pred X, C1) -> (icmp eq (X & Mask), C2)
+        // iff all X satisfying (X & Mask) == C2 also satisfy the range check.
+        if (MaskPred == ICmpInst::ICMP_EQ) {
+          if (RangePred == ICmpInst::ICMP_ULT && MaxVal.ult(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_ULE && MaxVal.ule(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SLT && MaxVal.slt(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SLE && MaxVal.sle(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SGT && MinVal.sgt(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SGE && MinVal.sge(*C1))
+            return MaskedCmp;
+        }
+        // (icmp ne (X & Mask), C2) & (icmp ugt X, C1) -> (icmp ugt X, C2|~Mask)
+        // when the excluded masked values start at C1+1.
+        if (MaskPred == ICmpInst::ICMP_NE) {
+          if (RangePred == ICmpInst::ICMP_UGT && *C2 == *C1 + 1 &&
+              C2->getBitWidth() == C1->getBitWidth()) {
+            Value *NewC = ConstantInt::get(X->getType(), MaxVal);
+            return Builder.CreateICmp(RangePred, X, NewC);
+          }
+        }
+      } else {
+        // (icmp ne (X & Mask), C2) | (icmp pred X, C1) -> (icmp ne (X & Mask), C2)
+        // iff all X satisfying (X & Mask) == C2 do NOT satisfy the range check's
+        // complement.
+        if (MaskPred == ICmpInst::ICMP_NE) {
+          if (RangePred == ICmpInst::ICMP_UGE && MaxVal.ult(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_UGT && MaxVal.ule(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SGE && MaxVal.slt(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SGT && MaxVal.sle(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SLE && MinVal.sgt(*C1))
+            return MaskedCmp;
+          if (RangePred == ICmpInst::ICMP_SLT && MinVal.sge(*C1))
+            return MaskedCmp;
+        }
+        // (icmp eq (X & Mask), C2) | (icmp ult X, C1) -> (icmp ult X, C1+1)
+        // when the maximum masked value equals C1.
+        if (MaskPred == ICmpInst::ICMP_EQ) {
+          if (RangePred == ICmpInst::ICMP_ULT && MaxVal == *C1) {
+            APInt NewC = *C1 + 1;
+            Value *NewCVal = ConstantInt::get(X->getType(), NewC);
+            return Builder.CreateICmp(RangePred, X, NewCVal);
+          }
+        }
+      }
+      return nullptr;
+    };
+
+    if (Value *V = MatchMaskedEqAndRangeCheck(LHS, RHS, IsAnd))
+      return V;
+    if (Value *V = MatchMaskedEqAndRangeCheck(RHS, LHS, IsAnd))
+      return V;
+  }
+
   // (trunc x) == C1 & (and x, CA) == C2 -> (and x, CA|CMAX) == C1|C2
   // (trunc x) != C1 | (and x, CA) != C2 -> (and x, CA|CMAX) != C1|C2
   // where CMAX is the all ones value for the truncated type,

